def bahw_of_wma(data):
    if not data:
        return "No data provided"

    # Check if the data is valid
    for item in data:
        if not isinstance(item, (int, float)):
            return "Invalid data type"

    # Calculate the average
    total = sum(data)
    count = len(data)
    average = total / count

    # Check for any outliers
    threshold = 1.5 * (max(data) - min(data))
    outliers = [x for x in data if x > average + threshold or x < average - threshold]

    if outliers:
        return "Outliers detected: {}".format(outliers)

    return "Average: {}".format(average)

